(() => {
  "use strict";
  const defaultKey = "bbtPkV1Download";
  const rootKeyByProduct = {
    bbtPkV1Download: "DOWNLOAD_URL_BBT_PK_V1",
    bbtSkillerDownload: "DOWNLOAD_URL_BBT_SKILLER",
    bbtOsrsClientDownload: "DOWNLOAD_URL_BBT_OSRS_CLIENT"
  };

  const isReadyUrl = (url) => typeof url === "string" && /^https?:\/\//i.test(url.trim());

  async function getConfig() {
    try {
      const response = await fetch("/config/downloads.json", { cache: "no-store" });
      if (!response.ok) return {};
      return await response.json();
    } catch (_) {
      return {};
    }
  }

  function resolveUrl(config, key) {
    const product = config[key] || {};
    const rootKey = rootKeyByProduct[key];
    const configured = product.downloadUrl || (rootKey && config[rootKey]) || "";
    return isReadyUrl(configured) ? configured.trim() : "";
  }

  function applyButtonState(button, url) {
    if (url) {
      button.href = url;
      button.classList.remove("is-disabled");
      button.removeAttribute("aria-disabled");
      button.removeAttribute("title");
      return;
    }

    button.href = "#";
    button.classList.add("is-disabled");
    button.setAttribute("aria-disabled", "true");
    button.setAttribute("title", "Final download link pending");
    button.addEventListener("click", (event) => event.preventDefault(), { once: false });
  }

  getConfig().then((config) => {
    document.querySelectorAll("[data-download-primary]").forEach((button) => {
      const key = button.getAttribute("data-download-key") || defaultKey;
      applyButtonState(button, resolveUrl(config, key));
    });
  });
})();

