.download-page { min-height:100vh; color:#f5f9ff; background: radial-gradient(circle at 18% -12%, rgba(178,74,28,.22), transparent 34%), radial-gradient(circle at 85% 4%, rgba(123,190,255,.14), transparent 36%), linear-gradient(180deg,#071424 0%,#0b1b2e 54%,#071424 100%); }
.download-container { width:min(calc(100% - clamp(28px,5vw,80px)),1160px); margin-inline:auto; }
.download-topbar { position:sticky; top:0; z-index:20; border-bottom:1px solid rgba(167,210,255,.16); background:rgba(6,16,30,.80); backdrop-filter:blur(16px); }
.topbar-inner { min-height:76px; display:flex; align-items:center; justify-content:space-between; gap:18px; }
.download-brand { display:inline-flex; align-items:center; gap:12px; font-weight:950; letter-spacing:-.03em; }
.download-brand img { width:42px; height:42px; border-radius:12px; }
.download-nav { display:flex; align-items:center; gap:8px; flex-wrap:wrap; }
.download-nav a { padding:8px 11px; border-radius:999px; border:1px solid rgba(167,210,255,.18); color:#d9e6f5; font-weight:850; }
.download-nav a:hover { color:#fff; border-color:rgba(178,74,28,.56); background:rgba(178,74,28,.12); }
.download-main { padding:clamp(44px,7vw,84px) 0 clamp(58px,8vw,96px); }
.download-hero { display:grid; grid-template-columns:minmax(0,1.24fr) minmax(260px,.76fr); gap:clamp(20px,4vw,44px); align-items:stretch; margin-bottom:22px; }
.hero-copy,.welcome-card,.download-card { border:1px solid rgba(167,210,255,.18); background:linear-gradient(180deg,rgba(11,27,46,.78),rgba(8,18,32,.92)); box-shadow:0 22px 64px rgba(0,0,0,.28); border-radius:24px; }
.hero-copy { padding:clamp(24px,4vw,42px); }
.download-eyebrow { display:inline-flex; width:fit-content; padding:7px 11px; border-radius:999px; border:1px solid rgba(178,74,28,.44); background:rgba(178,74,28,.14); color:#ffd3be; font-weight:950; font-size:.82rem; letter-spacing:.055em; text-transform:uppercase; }
.download-hero h1 { max-width:800px; margin:16px 0 12px; font-size:clamp(2.45rem,6vw,5.25rem); line-height:.94; letter-spacing:-.07em; }
.download-lede { max-width:72ch; color:#f5f9ff; font-size:clamp(1.08rem,1.55vw,1.28rem); font-weight:840; }
.download-intro { max-width:72ch; color:#d9e6f5; font-size:1rem; }
.release-badges { display:flex; flex-wrap:wrap; gap:9px; margin:22px 0 20px; }
.release-badges span { border:1px solid rgba(167,210,255,.20); background:rgba(255,255,255,.045); color:#d9e6f5; border-radius:999px; padding:8px 11px; font-size:.92rem; }
.download-actions { display:flex; flex-wrap:wrap; gap:12px; margin:20px 0 14px; }
.download-btn { min-height:50px; display:inline-flex; align-items:center; justify-content:center; gap:9px; padding:13px 20px; border-radius:999px; border:1px solid rgba(167,210,255,.28); font-weight:950; cursor:pointer; transition:transform .18s ease,filter .18s ease,background .18s ease; }
.download-btn:hover { transform:translateY(-1px); }
.download-btn.primary { background:linear-gradient(180deg,#CC5A2A 0%,#B24A1C 100%); border-color:rgba(178,74,28,.72); color:#fff; box-shadow:0 16px 42px rgba(178,74,28,.26), inset 0 1px 0 rgba(255,255,255,.18); }
.download-note { margin:0; color:#ffd3be; font-weight:850; }
.welcome-card { padding:clamp(24px,3.4vw,38px); display:grid; place-items:center; text-align:center; align-content:center; gap:12px; }
.welcome-card img { width:min(180px,52vw); height:min(180px,52vw); object-fit:contain; border-radius:32px; background:rgba(6,16,30,.44); padding:14px; }
.welcome-card h2 { margin:4px 0 0; font-size:clamp(1.55rem,3vw,2.4rem); letter-spacing:-.05em; }
.welcome-card p { margin:0; color:#d9e6f5; font-weight:850; }
.download-grid { display:grid; grid-template-columns:repeat(2,minmax(0,1fr)); gap:18px; }
.download-card { padding:clamp(20px,3vw,30px); }
.download-card.wide { grid-column:1/-1; }
.download-card h2 { margin:0 0 12px; font-size:clamp(1.35rem,2.1vw,2.05rem); letter-spacing:-.045em; }
.download-card p,.download-card li { color:#d9e6f5; }
.download-card ol,.download-card ul { margin:10px 0 0; padding-left:1.35rem; }
.download-card li + li { margin-top:8px; }
.download-footer { border-top:1px solid rgba(167,210,255,.16); color:#adc3dc; padding:24px 0; }
.footer-inner { display:flex; justify-content:space-between; gap:16px; flex-wrap:wrap; }
@media (max-width:860px){ .topbar-inner{align-items:flex-start; flex-direction:column; padding:15px 0;} .download-hero,.download-grid{grid-template-columns:1fr;} .download-card.wide{grid-column:auto;} .download-btn{width:100%;} }


/* V86_MULTI_PRODUCT_DOWNLOAD_PAGES_PREVIEW_2026_05_24
   Multi-product download page polish.
   Scope: download pages only. Keeps heavy ZIP files outside the site and centralizes URLs in config/downloads.json.
*/
.download-page {
  background:
    radial-gradient(circle at 18% -12%, rgba(178,74,28,.24), transparent 34%),
    radial-gradient(circle at 88% 6%, rgba(123,190,255,.12), transparent 34%),
    linear-gradient(180deg,#071424 0%,#0b1b2e 54%,#071424 100%);
}

.download-topbar {
  box-shadow: 0 10px 36px rgba(0,0,0,.20);
}

.download-brand span {
  color: #f5f9ff;
}

.download-main {
  padding-top: clamp(36px, 5vw, 72px);
}

.hero-copy,
.welcome-card,
.download-card {
  border-color: rgba(167,210,255,.16);
  background:
    radial-gradient(circle at top right, rgba(178,74,28,.09), transparent 40%),
    linear-gradient(180deg,rgba(11,27,46,.80),rgba(8,18,32,.94));
  box-shadow: 0 24px 70px rgba(0,0,0,.28), inset 0 1px 0 rgba(255,255,255,.045);
}

.hero-copy {
  border-color: rgba(178,74,28,.26);
}

.download-eyebrow,
.product-pill {
  border-color: rgba(178,74,28,.44);
  background: rgba(178,74,28,.14);
  color:#ffd3be;
}

.download-hero h1 {
  text-wrap: balance;
}

.download-lede,
.download-intro {
  text-wrap: pretty;
}

.release-badges span {
  border-color: rgba(178,74,28,.24);
  background: rgba(178,74,28,.06);
}

.release-badges strong,
.download-card h2,
.welcome-card h2 {
  color:#ffb38a;
}

.download-btn.primary {
  background: linear-gradient(180deg,#CC5A2A 0%,#B24A1C 100%);
  border-color:rgba(178,74,28,.72);
  color:#fff;
  box-shadow:0 16px 42px rgba(178,74,28,.26), inset 0 1px 0 rgba(255,255,255,.18);
}

.download-btn.is-disabled {
  opacity:.58;
  cursor:not-allowed;
  filter:saturate(.65);
}

.download-btn.is-disabled:hover {
  transform:none;
}

.download-note.pending-note {
  color:#ffd3be;
}

.download-card {
  transition: border-color .16s ease, transform .16s ease, background .16s ease;
}

.download-card:hover {
  border-color: rgba(178,74,28,.30);
  transform: translateY(-1px);
}

.download-card.wide {
  border-color: rgba(178,74,28,.24);
}

.download-card ol,
.download-card ul {
  padding-left: 1.2rem;
}

.download-card li + li {
  margin-top: .48rem;
}

.download-footer {
  border-top: 1px solid rgba(167,210,255,.12);
  background:rgba(6,16,30,.52);
}

@media (max-width: 860px) {
  .download-hero {
    grid-template-columns: 1fr;
  }
  .topbar-inner {
    align-items:flex-start;
    flex-direction:column;
    padding-block: 14px;
  }
  .download-nav {
    width:100%;
    overflow-x:auto;
    flex-wrap:nowrap;
    padding-bottom:4px;
  }
  .download-nav a {
    white-space:nowrap;
  }
  .download-actions {
    display:grid;
    grid-template-columns:1fr;
  }
  .download-btn {
    width:100%;
  }
}

@media (max-width: 520px) {
  .download-container {
    width:min(calc(100% - 24px),1160px);
  }
  .download-hero h1 {
    font-size:clamp(2.25rem,13vw,3.25rem);
  }
  .release-badges span {
    width:100%;
  }
}


